#include <bits/stdc++.h>
using namespace std;

const int N=780;

int n,a[N][N],sum,f[N][N],g[N][N];

int main(){
	scanf("%d",&n);
	for(int j=2;j<=n;j++)
		for(int i=1;i<j;i++){
			scanf("%d",&a[i][j]);
			sum+=max(-a[i][j],0);
		}
	memset(f,63,sizeof(f));
	for(int i=1;i<=n;i++){
		f[i][i]=0;
		for(int j=i+1;j<=n;j++)
			g[i][j]=g[i][j-1]+min(a[i][j],0);
	}
	for(int l=2;l<=n;l++)
		for(int i=1;i+l-1<=n;i++){
			int j=i+l-1;
			for(int k=i;k<j;k++)
				f[i][j]=min(f[i][j],f[i][k]+f[k+1][j]+a[i][k+1]+g[i][j]-g[i][k+1]);
		}
	printf("%d",sum+f[1][n]);
	return 0;
}
